const input = $input.first().json;
const event = input.event || input.body?.event || 'review.ai.alert';
const reviewId = input.reviewId || input.body?.reviewId;
const error = input.error || input.body?.error;
const flagged = input.flagged || input.body?.flagged;

let subject = 'Review AI Alert';
let body = `Event: ${event}\n`;

if (reviewId) body += `Review ID: ${reviewId}\n`;
if (flagged) body += 'A review was flagged by AI moderation.\n';
if (error) body += `Error: ${error}\n`;
if (input.body?.nextRetryAt) {
  body += `Next retry: ${new Date(input.body.nextRetryAt).toLocaleString()}\n`;
}

if (event === 'review.ai.failed') subject = 'Review AI processing failed';
if (flagged) subject = 'Review flagged for moderation';
if (event === 'backlog') subject = 'Review AI queue backlog alert';

return [{ json: { subject, body } }];
